"""Reusable responsive piston animation for gas-state comparisons."""
from physics_playground.canvas.player import build_player_document
SCENE=r"""
const scene={draw(ctx,s){const w=s.transform.width,h=s.transform.height,c=s.config.gasContainer||{},left=w*.25,right=w*.75,bottom=h*.82,maxV=Math.max(c.volumeA,c.volumeB,.001),v=c.volumeA+(c.volumeB-c.volumeA)*s.fraction,gasH=80+v/maxV*h*.48,top=bottom-gasH;ctx.clearRect(0,0,w,h);ctx.fillStyle='#FAFAFA';ctx.fillRect(0,0,w,h);ctx.strokeStyle='#263238';ctx.lineWidth=5;ctx.strokeRect(left,h*.12,right-left,bottom-h*.12);ctx.fillStyle='rgba(255,193,7,.3)';ctx.fillRect(left,top,right-left,bottom-top);ctx.fillStyle='#546E7A';ctx.fillRect(left-15,top-8,right-left+30,16);const rand=seededRandom(c.seed||1);ctx.fillStyle='#D55E00';for(let i=0;i<Math.min(80,c.particles||30);i++){const x=left+12+rand()*(right-left-24),y=top+12+rand()*Math.max(10,bottom-top-24);ctx.beginPath();ctx.arc(x,y,3,0,Math.PI*2);ctx.fill()}ctx.fillStyle='#111';ctx.font='14px sans-serif';ctx.fillText(`P ${(c.pressureA+(c.pressureB-c.pressureA)*s.fraction).toFixed(1)} kPa`,left,30);ctx.fillText(`V ${(v*1000).toFixed(1)} L`,left+150,30);ctx.fillText(`T ${(c.tempA+(c.tempB-c.tempA)*s.fraction).toFixed(1)} K`,left+285,30);}};
"""
def build_gas_document(*,pressure_a_kpa:float,pressure_b_kpa:float,volume_a_m3:float,volume_b_m3:float,temp_a_k:float,temp_b_k:float,particles:int,message:str,seed:int)->str:
    config={"durationMs":1700,"autoplay":False,"seed":seed,"tracks":[{"id":"gas-transition","label":"Gas state transition","x":[0,1]}],"events":[],"completionMessage":message,"gasContainer":{"pressureA":pressure_a_kpa,"pressureB":pressure_b_kpa,"volumeA":volume_a_m3,"volumeB":volume_b_m3,"tempA":temp_a_k,"tempB":temp_b_k,"particles":particles,"seed":seed},"view":{"minimum":0,"maximum":1}}
    return build_player_document(config=config,scene_javascript=SCENE,logical_width=720,logical_height=520,accessible_label="Gas piston changing from state A to state B. "+message,idle_hint="Press Play to animate the gas-state change")
